SELECT site_name, contact_email, acreage
FROM site_info
WHERE irrigation_system = 'Sprinkler Irrigation' AND soil_type = 'Loam';

SELECT DISTINCT site_id, site_name
FROM site_info
WHERE site_name LIKE '%Sunny%';

SELECT si.site_name, da.crop_type
FROM site_info si
JOIN data_analysis da ON si.site_id = da.site_id;

SELECT MAX(avg_temperature) AS max_avg_temperature
FROM (
    SELECT site_id, AVG(temperature_plant1 + temperature_plant2 + temperature_plant6) AS avg_temperature
    FROM sensor_readings
    GROUP BY site_id
) AS subquery;

SELECT sr.temperature_plant1, si.site_name
FROM sensor_readings sr
INNER JOIN site_info si ON sr.site_id = si.site_id;
